const template_049 =
  "/**\n * @component Panel\n * @layer 2\n * @depends theme-seed\n * @description Dense secondary surface for sidebars, filter rails, and grouped dashboard controls.\n */\n\nimport type { ComponentChildren, JSX, VNode } from 'preact';\nimport { cn } from '../../lib/cn.ts';\n\nexport type PanelTone = 'default' | 'muted' | 'raised';\n\nexport interface PanelProps extends Omit<JSX.HTMLAttributes<HTMLDivElement>, 'class' | 'children'> {\n  children: ComponentChildren;\n  class?: string;\n  tone?: PanelTone;\n}\n\ninterface PanelSectionProps extends Omit<JSX.HTMLAttributes<HTMLDivElement>, 'class' | 'children'> {\n  children: ComponentChildren;\n  class?: string;\n}\n\ninterface PanelTextProps\n  extends Omit<JSX.HTMLAttributes<HTMLParagraphElement>, 'class' | 'children'> {\n  children: ComponentChildren;\n  class?: string;\n}\n\nconst TONE_CLASSES: Record<PanelTone, string | undefined> = {\n  default: undefined,\n  muted: 'ns-panel--muted',\n  raised: 'ns-panel--raised',\n};\n\nfunction PanelRoot({ children, class: className, tone = 'default', ...props }: PanelProps): VNode {\n  return <div {...props} class={cn('ns-panel', TONE_CLASSES[tone], className)}>{children}</div>;\n}\n\nexport function PanelHeader({ children, class: className, ...props }: PanelSectionProps): VNode {\n  return <div {...props} class={cn('ns-panel__header', className)}>{children}</div>;\n}\n\nexport function PanelTitle({ children, class: className, ...props }: PanelTextProps): VNode {\n  return <p {...props} class={cn('ns-panel__title', className)}>{children}</p>;\n}\n\nexport function PanelDescription({ children, class: className, ...props }: PanelTextProps): VNode {\n  return <p {...props} class={cn('ns-panel__description', className)}>{children}</p>;\n}\n\nexport function PanelBody({ children, class: className, ...props }: PanelSectionProps): VNode {\n  return <div {...props} class={cn('ns-panel__body', className)}>{children}</div>;\n}\n\nexport function PanelFooter({ children, class: className, ...props }: PanelSectionProps): VNode {\n  return <div {...props} class={cn('ns-panel__footer', className)}>{children}</div>;\n}\n\ntype PanelNamespace =\n  & typeof PanelRoot\n  & Readonly<{\n    Header: typeof PanelHeader;\n    Title: typeof PanelTitle;\n    Description: typeof PanelDescription;\n    Body: typeof PanelBody;\n    Footer: typeof PanelFooter;\n  }>;\n\nexport const Panel: PanelNamespace = Object.assign(PanelRoot, {\n  Header: PanelHeader,\n  Title: PanelTitle,\n  Description: PanelDescription,\n  Body: PanelBody,\n  Footer: PanelFooter,\n});\n";
const template_050 =
  '.ns-progress {\n  width: 100%;\n}\n\n.ns-progress__track {\n  position: relative;\n  display: block;\n  width: 100%;\n  overflow: hidden;\n  border-radius: var(--ns-radius-full);\n  background: color-mix(in srgb, var(--ns-border-hover) 90%, transparent);\n}\n\n.ns-progress--sm .ns-progress__track {\n  height: 0.325rem;\n}\n\n.ns-progress--md .ns-progress__track {\n  height: 0.5rem;\n}\n\n.ns-progress--lg .ns-progress__track {\n  height: 0.7rem;\n}\n\n.ns-progress__bar {\n  display: block;\n  height: 100%;\n  border-radius: inherit;\n  background: var(--ns-primary);\n  transition: width var(--ns-ease-normal);\n}\n\n.ns-progress--secondary .ns-progress__bar {\n  background: var(--ns-secondary);\n}\n\n.ns-progress--success .ns-progress__bar {\n  background: var(--ns-success);\n}\n\n.ns-progress--warning .ns-progress__bar {\n  background: var(--ns-warning);\n}\n\n.ns-progress--destructive .ns-progress__bar {\n  background: var(--ns-destructive);\n}\n\n.ns-progress--indeterminate .ns-progress__bar {\n  width: 42%;\n  animation: ns-progress-indeterminate 1.2s ease-in-out infinite;\n}\n\n@keyframes ns-progress-indeterminate {\n  0% {\n    transform: translateX(-120%);\n  }\n\n  50% {\n    transform: translateX(30%);\n  }\n\n  100% {\n    transform: translateX(180%);\n  }\n}\n\n/* Reduced motion: indeterminate sweep becomes a static partial fill. */\n@media (prefers-reduced-motion: reduce) {\n  .ns-progress--indeterminate .ns-progress__bar {\n    animation: none;\n    width: 42%;\n    transform: translateX(70%);\n  }\n}\n';
const template_051 =
  "/**\n * @component Progress\n * @layer 2\n * @depends theme-seed\n * @description Determinate or indeterminate progress indicator for jobs, uploads, and deferred flows.\n */\n\nimport type { JSX, VNode } from 'preact';\nimport { cn } from '../../lib/cn.ts';\n\nexport type ProgressVariant = 'primary' | 'secondary' | 'success' | 'warning' | 'destructive';\nexport type ProgressSize = 'sm' | 'md' | 'lg';\n\nexport interface ProgressProps\n  extends Omit<JSX.HTMLAttributes<HTMLDivElement>, 'class' | 'children'> {\n  class?: string;\n  indeterminate?: boolean;\n  label?: string;\n  max?: number;\n  size?: ProgressSize;\n  value?: number;\n  variant?: ProgressVariant;\n}\n\nconst SIZE_CLASSES: Record<ProgressSize, string> = {\n  sm: 'ns-progress--sm',\n  md: 'ns-progress--md',\n  lg: 'ns-progress--lg',\n};\n\nconst VARIANT_CLASSES: Record<ProgressVariant, string | undefined> = {\n  primary: undefined,\n  secondary: 'ns-progress--secondary',\n  success: 'ns-progress--success',\n  warning: 'ns-progress--warning',\n  destructive: 'ns-progress--destructive',\n};\n\nfunction clamp(value: number, min: number, max: number): number {\n  return Math.min(Math.max(value, min), max);\n}\n\nexport function Progress({\n  class: className,\n  indeterminate = false,\n  label = 'Progress',\n  max = 100,\n  size = 'md',\n  value = 0,\n  variant = 'primary',\n  ...props\n}: ProgressProps): VNode {\n  const safeMax = max > 0 ? max : 100;\n  const normalizedValue = clamp(value, 0, safeMax);\n  const width = `${(normalizedValue / safeMax) * 100}%`;\n\n  return (\n    <div\n      {...props}\n      role='progressbar'\n      aria-label={label}\n      aria-valuemin={0}\n      aria-valuemax={safeMax}\n      aria-valuenow={indeterminate ? undefined : normalizedValue}\n      class={cn(\n        'ns-progress',\n        SIZE_CLASSES[size],\n        VARIANT_CLASSES[variant],\n        indeterminate && 'ns-progress--indeterminate',\n        className,\n      )}\n    >\n      <span class='ns-progress__track'>\n        <span class='ns-progress__bar' style={indeterminate ? undefined : { width }} />\n      </span>\n    </div>\n  );\n}\n";
