const template_057 =
  "/**\n * @component Search\n * @layer 2\n * @depends theme-seed\n * @description Compact nav search affordance: a button styled as an input that\n * opens the command palette, with a leading search glyph and a trailing ⌘K\n * keyboard hint. Presentational — the consumer wires onOpen to its palette\n * (and any global ⌘K listener lives in an app island).\n */\n\nimport type { JSX, VNode } from 'preact';\nimport { cn } from '../../lib/cn.ts';\n\ninterface SearchProps extends Omit<JSX.HTMLAttributes<HTMLButtonElement>, 'class' | 'onClick'> {\n  /** Placeholder/label copy shown inside the field. */\n  placeholder?: string;\n  /** Keyboard hint glyphs, e.g. `⌘K`. Hidden when empty. */\n  shortcut?: string;\n  /** Invoked when the field is activated (opens the palette). */\n  onOpen?: () => void;\n  class?: string;\n}\n\n/**\n * Renders the compact nav search trigger.\n */\nexport function Search(\n  { placeholder = 'Search…', shortcut = '⌘K', onOpen, class: className, ...props }: SearchProps,\n): VNode {\n  return (\n    <button\n      {...props}\n      type='button'\n      class={cn('ns-search', className)}\n      onClick={() => onOpen?.()}\n    >\n      <span class='ns-search__icon' aria-hidden='true'>⌕</span>\n      <span class='ns-search__label'>{placeholder}</span>\n      {shortcut ? <kbd class='ns-kbd ns-search__kbd'>{shortcut}</kbd> : null}\n    </button>\n  );\n}\n";
const template_058 =
  "import type { JSX, VNode } from 'preact';\nimport { cn } from '../../lib/cn.ts';\nimport type { Renderable } from '../../lib/public-types.ts';\n\ninterface SectionDividerProps\n  extends Omit<JSX.HTMLAttributes<HTMLDivElement>, 'class' | 'children'> {\n  label: Renderable;\n  class?: string;\n  lineClass?: string;\n}\n\n/**\n * Renders a labeled divider for detail and form sections.\n */\nexport function SectionDivider(\n  { label, class: className, lineClass, ...props }: SectionDividerProps,\n): VNode {\n  return (\n    <div {...props} class={cn('flex items-baseline gap-4', className)}>\n      <span class='text-[0.65rem] font-mono uppercase tracking-[0.12em] text-ns-muted-fg'>\n        {label}\n      </span>\n      <div class={cn('h-px flex-1 bg-ns-border', lineClass)} />\n    </div>\n  );\n}\n";
const template_059 =
  "/**\n * @component Select\n * @layer 2\n * @depends theme-seed\n * @description Native select wrapper with token-driven focus and error states.\n */\n\nimport type { JSX, VNode } from 'preact';\nimport { cn } from '../../lib/cn.ts';\n\n/**\n * Native select option metadata.\n */\nexport interface SelectOption {\n  /** Serialized option value. */\n  value: string;\n  /** Visible option label. */\n  label: string;\n  /** Disables selection for this option. */\n  disabled?: boolean;\n}\n\ninterface SelectProps\n  extends Omit<JSX.SelectHTMLAttributes<HTMLSelectElement>, 'class' | 'children'> {\n  class?: string;\n  error?: boolean;\n  options: readonly SelectOption[];\n  placeholder?: string;\n  selectedValues?: readonly string[];\n  readonly [key: `data-${string}`]: string | number | boolean | undefined;\n}\n\n/**\n * Renders a token-aware native select control.\n */\nexport function Select({\n  class: className,\n  error = false,\n  options,\n  placeholder,\n  value,\n  defaultValue,\n  selectedValues,\n  ...props\n}: SelectProps): VNode {\n  const resolvedSelectedValues = new Set(\n    normalizeSelectedValues(\n      selectedValues ?? value ?? defaultValue,\n      props.multiple === true,\n    ),\n  );\n\n  return (\n    <select\n      {...props}\n      value={value}\n      defaultValue={defaultValue}\n      class={cn('ns-select', error && 'ns-select--error', className)}\n    >\n      {\n        /* Keep option-level selected attributes for SSR so the initial HTML is correct\n          before hydration or browser reconciliation touches the control. */\n      }\n      {placeholder\n        ? <option value='' selected={resolvedSelectedValues.size === 0}>{placeholder}</option>\n        : null}\n      {options.map((option) => (\n        <option\n          key={option.value}\n          value={option.value}\n          disabled={option.disabled}\n          selected={resolvedSelectedValues.has(option.value)}\n        >\n          {option.label}\n        </option>\n      ))}\n    </select>\n  );\n}\n\nfunction normalizeSelectedValues(\n  value: unknown,\n  multiple: boolean,\n): string[] {\n  if (Array.isArray(value)) {\n    return multiple ? [...value] : value.length > 0 ? [value[0] ?? ''] : [];\n  }\n\n  if (typeof value === 'string') {\n    return value.length > 0 ? [value] : [];\n  }\n\n  return [];\n}\n";
