const template_061 =
  "/**\n * @component Separator\n * @layer 2\n * @depends theme-seed\n * @description Lightweight divider for separating content groups in cards, forms, and toolbars.\n */\n\nimport type { JSX, VNode } from 'preact';\nimport { cn } from '../../lib/cn.ts';\n\ninterface SeparatorProps extends Omit<JSX.HTMLAttributes<HTMLDivElement>, 'class' | 'children'> {\n  class?: string;\n  orientation?: 'horizontal' | 'vertical';\n}\n\n/**\n * Renders a horizontal or vertical separator.\n */\nexport function Separator(\n  { class: className, orientation = 'horizontal', ...props }: SeparatorProps,\n): VNode {\n  return (\n    <div\n      {...props}\n      role='separator'\n      aria-orientation={orientation}\n      class={cn(\n        'ns-separator',\n        orientation === 'vertical' && 'ns-separator--vertical',\n        className,\n      )}\n    />\n  );\n}\n";
const template_062 =
  "/* -------------------------------------------------------------------------- */\n/* Sheet — side-docked inspection panel                                       */\n/* -------------------------------------------------------------------------- */\n\ndialog[data-part='content'][data-side] {\n  position: fixed;\n  z-index: 50;\n  margin: 0;\n  padding: 0;\n  border: none;\n  background: var(--ns-card);\n  color: var(--ns-card-fg);\n  box-shadow:\n    -8px 0 30px color-mix(in srgb, var(--ns-gray-12) 35%, transparent),\n    0 0 0 1px color-mix(in srgb, var(--ns-gray-12) 10%, transparent);\n  overflow-y: auto;\n  -webkit-overflow-scrolling: touch;\n  max-width: 100vw;\n  max-height: 100vh;\n}\n\ndialog[data-part='content'][data-side]::backdrop {\n  background: color-mix(in srgb, var(--ns-gray-12) 55%, transparent);\n  backdrop-filter: blur(4px);\n  -webkit-backdrop-filter: blur(4px);\n}\n\n/* Open state: animate in */\ndialog[data-part='content'][data-side][open] {\n  animation: ns-sheet-enter 220ms cubic-bezier(0.16, 1, 0.3, 1) forwards;\n}\n\ndialog[data-part='content'][data-side][open]::backdrop {\n  animation: ns-sheet-backdrop-in 200ms ease forwards;\n}\n\n@keyframes ns-sheet-backdrop-in {\n  from {\n    opacity: 0;\n  }\n  to {\n    opacity: 1;\n  }\n}\n\n/* Right side (desktop default) */\ndialog[data-part='content'][data-side='right'] {\n  inset: 0 0 0 auto;\n  width: min(520px, 92vw);\n  height: 100vh;\n  height: 100dvh;\n  border-left: 1px solid var(--ns-border-hover);\n  border-radius: var(--ns-radius-xl) 0 0 var(--ns-radius-xl);\n}\n\n@keyframes ns-sheet-enter {\n  from {\n    opacity: 0;\n    transform: translateX(100%);\n  }\n  to {\n    opacity: 1;\n    transform: translateX(0);\n  }\n}\n\n/* Bottom side (mobile / explicit) */\ndialog[data-part='content'][data-side='bottom'] {\n  inset: auto 0 0 0;\n  width: 100%;\n  max-height: 85vh;\n  max-height: 85dvh;\n  border-top: 1px solid var(--ns-border-hover);\n  border-radius: var(--ns-radius-xl) var(--ns-radius-xl) 0 0;\n}\n\ndialog[data-part='content'][data-side='bottom'][open] {\n  animation: ns-sheet-enter-bottom 220ms cubic-bezier(0.16, 1, 0.3, 1) forwards;\n}\n\n@keyframes ns-sheet-enter-bottom {\n  from {\n    opacity: 0;\n    transform: translateY(100%);\n  }\n  to {\n    opacity: 1;\n    transform: translateY(0);\n  }\n}\n\n/* Sheet inner structure */\n.ns-sheet__header {\n  display: flex;\n  align-items: flex-start;\n  justify-content: space-between;\n  gap: var(--ns-space-3);\n  padding: var(--ns-space-5) var(--ns-space-6);\n  border-bottom: 1px solid var(--ns-border);\n  position: sticky;\n  top: 0;\n  background: var(--ns-card);\n  z-index: 1;\n}\n\n.ns-sheet__body {\n  padding: var(--ns-space-5) var(--ns-space-6);\n}\n\n.ns-sheet__footer {\n  display: flex;\n  align-items: center;\n  gap: var(--ns-space-3);\n  padding: var(--ns-space-4) var(--ns-space-6);\n  border-top: 1px solid var(--ns-border);\n  position: sticky;\n  bottom: 0;\n  background: var(--ns-card);\n  z-index: 1;\n}\n\n/* Drag handle indicator for bottom sheet */\ndialog[data-part='content'][data-side='bottom']::before {\n  content: '';\n  display: block;\n  width: 2.5rem;\n  height: 0.25rem;\n  border-radius: 9999px;\n  background: var(--ns-border-strong);\n  margin: var(--ns-space-2) auto var(--ns-space-1);\n}\n\n/* Reduced motion: enter animations are one-shot with fill-mode forwards, so\n   they jump to their end state instead of being removed. */\n@media (prefers-reduced-motion: reduce) {\n  dialog[data-part='content'][data-side][open],\n  dialog[data-part='content'][data-side][open]::backdrop,\n  dialog[data-part='content'][data-side='bottom'][open] {\n    animation-duration: 0.01ms;\n  }\n}\n";
const template_063 =
  "import type { JSX, VNode } from 'preact';\nimport { cn } from '../../lib/cn.ts';\nimport type { ComponentResult, Renderable } from '../../lib/public-types.ts';\n\n/**\n * Sidebar navigation item metadata.\n */\nexport interface SidebarNavItem {\n  /** Destination URL for the navigation item. */\n  href: string;\n  /** Visible navigation label. */\n  label: string;\n  /** Optional leading icon for the item. */\n  icon?: Renderable;\n  /** Enables prefix matching for nested routes. */\n  matchPrefix?: boolean;\n  /** Optional custom active-state predicate. */\n  isActive?: (pathname: string) => boolean;\n}\n\n/**\n * Sidebar navigation section metadata.\n */\nexport interface SidebarNavSection {\n  /** Optional section label rendered above the grouped items. */\n  label?: string;\n  /** Ordered items within the section. */\n  items: readonly SidebarNavItem[];\n}\n\ninterface SidebarShellProps extends Omit<JSX.HTMLAttributes<HTMLDivElement>, 'class' | 'children'> {\n  children: Renderable;\n  class?: string;\n  pathname: string;\n  navigation: readonly SidebarNavSection[];\n  brand: Renderable;\n  brandBadge?: Renderable;\n  footer?: Renderable;\n  topbarStart?: Renderable;\n  topbarEnd?: Renderable;\n  contentId?: string;\n  navLabel?: string;\n}\n\nfunction isItemActive(pathname: string, item: SidebarNavItem): boolean {\n  if (item.isActive) {\n    return item.isActive(pathname);\n  }\n\n  if (item.matchPrefix) {\n    return pathname === item.href || pathname.startsWith(`${item.href}/`);\n  }\n\n  return pathname === item.href;\n}\n\nfunction SidebarShellNavGroup(\n  { label, items, pathname }: {\n    label?: string;\n    items: readonly SidebarNavItem[];\n    pathname: string;\n  },\n): VNode {\n  return (\n    <div class='ns-dashboard__nav-group' role='list'>\n      {label && <span class='ns-dashboard__nav-group-label'>{label}</span>}\n      {items.map((item) => {\n        const active = isItemActive(pathname, item);\n        return (\n          <a\n            key={item.href}\n            href={item.href}\n            role='listitem'\n            class={cn('ns-dashboard__nav-item', active && 'is-active')}\n            aria-current={active ? 'page' : undefined}\n          >\n            {item.icon && (\n              <span class='ns-dashboard__nav-icon' aria-hidden='true'>{item.icon}</span>\n            )}\n            <span class='ns-dashboard__nav-label'>{item.label}</span>\n          </a>\n        );\n      })}\n    </div>\n  );\n}\n\n/**\n * Renders the shared dashboard sidebar shell with navigation and topbar slots.\n */\nexport function SidebarShell(\n  {\n    children,\n    class: className,\n    pathname,\n    navigation,\n    brand,\n    brandBadge,\n    footer,\n    topbarStart,\n    topbarEnd,\n    contentId = 'main-content',\n    navLabel = 'Sidebar navigation',\n    ...props\n  }: SidebarShellProps,\n): ComponentResult {\n  return (\n    <div {...props} class={cn('ns-dashboard', className)}>\n      <div class='ns-dashboard__sidebar-backdrop' data-sidebar-backdrop aria-hidden='true' />\n\n      <aside class='ns-dashboard__sidebar' data-sidebar>\n        <div class='ns-dashboard__sidebar-header'>\n          <div class='flex min-w-0 items-center gap-3'>\n            {brand}\n          </div>\n          {brandBadge}\n        </div>\n\n        <nav class='ns-dashboard__sidebar-body' aria-label={navLabel}>\n          {navigation.map((section, index) => (\n            <div key={section.label ?? `section-${index}`}>\n              {index > 0 && <div class='ns-dashboard__nav-divider' role='separator' />}\n              <SidebarShellNavGroup\n                label={section.label}\n                items={section.items}\n                pathname={pathname}\n              />\n            </div>\n          ))}\n        </nav>\n\n        {footer && <div class='ns-dashboard__sidebar-footer'>{footer}</div>}\n      </aside>\n\n      <div class='ns-dashboard__main'>\n        <header class='ns-dashboard__topbar'>\n          <div class='flex min-w-0 items-center gap-3'>\n            {topbarStart}\n          </div>\n          <div class='flex items-center gap-2'>\n            {topbarEnd}\n          </div>\n        </header>\n\n        <main class='ns-dashboard__content' id={contentId}>\n          {children}\n        </main>\n      </div>\n    </div>\n  );\n}\n";
